namespace sv_56f701f909c64ffc9464135893dee42e.Services;

/// <summary>
/// Scoped service that holds the current warehouse selection for a single user circuit.
/// Each Blazor Server circuit gets its own instance, so users are fully isolated.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<Warehouse> AvailableWarehouses =
    [
        new("WH-A", "Warehouse A — East"),
        new("WH-B", "Warehouse B — West"),
        new("WH-C", "Warehouse C — Central"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public Warehouse CurrentWarehouse =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId);

    /// <summary>Raised when the selected warehouse changes. Subscribers must call StateHasChanged.</summary>
    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

public sealed record Warehouse(string Id, string Name);

namespace sv_56f701f909c64ffc9464135893dee42e.Services;

/// <summary>
/// Simulates a database query that returns how many items are below minimum stock levels.
/// Registered as scoped so each circuit gets a stable Random seed per session.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with random result 0–15
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

@using sv_56f701f909c64ffc9464135893dee42e.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label class="form-label mb-0 fw-semibold text-nowrap" for="warehouseSelect">Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="min-width: 200px;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChange;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
            await WarehouseState.SetWarehouseAsync(id);
    }

    private Task HandleStateChange()
    {
        InvokeAsync(StateHasChanged);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChange;
    }
}

@using sv_56f701f909c64ffc9464135893dee42e.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_count.HasValue && _count.Value > 0)
{
    <span class="badge rounded-pill bg-danger ms-2" title="Low-stock items">@_count.Value</span>
}
else if (_count.HasValue)
{
    <span class="badge rounded-pill bg-success ms-2" title="No low-stock items">0</span>
}

@code {
    private int? _count;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await RefreshCountAsync();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await RefreshCountAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshCountAsync()
    {
        _count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnWarehouseChanged()
    {
        // Restart polling with new warehouse
        StartPolling();
        await RefreshCountAsync();
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_56f701f909c64ffc9464135893dee42e.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            @WarehouseState.CurrentWarehouse.Name
        </h5>
        <p class="card-text text-muted">Site ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(_lowStockCount > 5 ? "danger" : _lowStockCount > 0 ? "warning" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@(_lowStockCount?.ToString() ?? "—")</h2>
                <p class="card-text">Low-Stock Alerts</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">@_lastChecked?.ToString("HH:mm:ss")</h2>
                <p class="card-text">Last Checked</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body text-center">
                <h2 class="display-4">10s</h2>
                <p class="card-text">Poll Interval</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private DateTime? _lastChecked;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await RefreshAsync();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnWarehouseChanged()
    {
        StartPolling();
        await RefreshAsync();
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

