@using sv_56f701f909c64ffc9464135893dee42e.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_count.HasValue && _count.Value > 0)
{
    <span class="badge rounded-pill bg-danger ms-2" title="Low-stock items">@_count.Value</span>
}
else if (_count.HasValue)
{
    <span class="badge rounded-pill bg-success ms-2" title="No low-stock items">0</span>
}

@code {
    private int? _count;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await RefreshCountAsync();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await RefreshCountAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshCountAsync()
    {
        _count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnWarehouseChanged()
    {
        // Restart polling with new warehouse
        StartPolling();
        await RefreshCountAsync();
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

